#!/usr/bin/env bash

# leaf.sh - Beautiful documentation generator for arty.sh projects
# Version: 1.0.0
# Generated by hammer.sh

set -euo pipefail

# Colors for output
RED='\033[0;31m'
GREEN='\033[0;32m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
CYAN='\033[0;36m'
NC='\033[0m' # No Color

# Configuration
PROJECT_DIR="${1:-.}"
OUTPUT_DIR="${PROJECT_DIR}/docs"
ARTY_YML="${PROJECT_DIR}/arty.yml"
README_MD="${PROJECT_DIR}/README.md"
LICENSE="${PROJECT_DIR}/LICENSE"
ASSETS_DIR="${PROJECT_DIR}/_assets"
ICON_DIR="${ASSETS_DIR}/icon"
EXAMPLES_DIR="${PROJECT_DIR}/examples"

# Helper functions
log_info() {
    echo -e "${BLUE}ℹ${NC} $1"
}

log_success() {
    echo -e "${GREEN}✓${NC} $1"
}

log_warn() {
    echo -e "${YELLOW}⚠${NC} $1"
}

log_error() {
    echo -e "${RED}✗${NC} $1"
}

# Parse YAML (simple parser for arty.yml)
parse_yaml() {
    local file="$1"
    local key="$2"
    
    if [[ ! -f "$file" ]]; then
        echo ""
        return
    fi
    
    # Simple YAML parsing for key: value pairs
    local value=$(grep "^${key}:" "$file" | head -1 | sed "s/^${key}://; s/^[[:space:]]*//; s/[[:space:]]*$//; s/^[\"']//; s/[\"']$//" || echo "")
    echo "$value"
}

# Convert markdown to HTML (basic conversion)
markdown_to_html() {
    local content="$1"
    
    # Escape HTML
    content=$(echo "$content" | sed 's/&/\&amp;/g; s/</\&lt;/g; s/>/\&gt;/g')
    
    # Convert headers
    content=$(echo "$content" | sed -E 's/^######[[:space:]]*(.*)/\<h6 class="text-lg font-semibold mt-4 mb-2 text-gray-800 dark:text-gray-200">\1<\/h6>/g')
    content=$(echo "$content" | sed -E 's/^#####[[:space:]]*(.*)/\<h5 class="text-xl font-semibold mt-4 mb-2 text-gray-800 dark:text-gray-200">\1<\/h5>/g')
    content=$(echo "$content" | sed -E 's/^####[[:space:]]*(.*)/\<h4 class="text-2xl font-semibold mt-6 mb-3 text-gray-800 dark:text-gray-200">\1<\/h4>/g')
    content=$(echo "$content" | sed -E 's/^###[[:space:]]*(.*)/\<h3 class="text-3xl font-semibold mt-8 mb-4 text-gray-900 dark:text-gray-100">\1<\/h3>/g')
    content=$(echo "$content" | sed -E 's/^##[[:space:]]*(.*)/\<h2 class="text-4xl font-bold mt-10 mb-4 text-gray-900 dark:text-gray-100">\1<\/h2>/g')
    content=$(echo "$content" | sed -E 's/^#[[:space:]]*(.*)/\<h1 class="text-5xl font-bold mt-12 mb-6 text-gray-900 dark:text-gray-100">\1<\/h1>/g')
    
    # Convert bold and italic
    content=$(echo "$content" | sed -E 's/\*\*([^*]+)\*\*/<strong class="font-semibold text-gray-900 dark:text-gray-100">\1<\/strong>/g')
    content=$(echo "$content" | sed -E 's/\*([^*]+)\*/<em class="italic text-gray-700 dark:text-gray-300">\1<\/em>/g')
    
    # Convert inline code
    content=$(echo "$content" | sed -E 's/`([^`]+)`/<code class="px-2 py-1 bg-gray-100 dark:bg-gray-800 text-pink-600 dark:text-pink-400 rounded text-sm font-mono">\1<\/code>/g')
    
    # Convert links
    content=$(echo "$content" | sed -E 's/\[([^]]+)\]\(([^)]+)\)/<a href="\2" class="text-blue-600 dark:text-blue-400 hover:underline">\1<\/a>/g')
    
    echo "$content"
}

# Get icon path
get_icon() {
    local icon_path=""
    
    if [[ -f "${ICON_DIR}/icon.svg" ]]; then
        icon_path="${ICON_DIR}/icon.svg"
    elif [[ -f "${ICON_DIR}/icon-v2.svg" ]]; then
        icon_path="${ICON_DIR}/icon-v2.svg"
    elif [[ -f "${ICON_DIR}/icon-simple.svg" ]]; then
        icon_path="${ICON_DIR}/icon-simple.svg"
    elif [[ -f "${ICON_DIR}/icon-alt.svg" ]]; then
        icon_path="${ICON_DIR}/icon-alt.svg"
    fi
    
    echo "$icon_path"
}

# Read file content safely
read_file() {
    local file="$1"
    if [[ -f "$file" ]]; then
        cat "$file"
    else
        echo ""
    fi
}

# Detect language from file extension
detect_language() {
    local file="$1"
    local ext="${file##*.}"
    
    case "$ext" in
        sh|bash) echo "bash" ;;
        js) echo "javascript" ;;
        py) echo "python" ;;
        rb) echo "ruby" ;;
        go) echo "go" ;;
        rs) echo "rust" ;;
        java) echo "java" ;;
        c|h) echo "c" ;;
        cpp|cc|cxx|hpp) echo "cpp" ;;
        cs) echo "csharp" ;;
        php) echo "php" ;;
        html) echo "html" ;;
        css) echo "css" ;;
        json) echo "json" ;;
        xml) echo "xml" ;;
        yaml|yml) echo "yaml" ;;
        md) echo "markdown" ;;
        *) echo "plaintext" ;;
    esac
}

# Scan source files
scan_source_files() {
    local files=()
    
    # Find all script files (excluding hidden directories and docs)
    while IFS= read -r -d $'\0' file; do
        local rel_path="${file#${PROJECT_DIR}/}"
        
        # Skip docs, node_modules, .git, etc.
        if [[ "$rel_path" =~ ^(docs|node_modules|\.git|\.)|\.min\. ]]; then
            continue
        fi
        
        files+=("$file")
    done < <(find "$PROJECT_DIR" -type f \( -name "*.sh" -o -name "*.bash" -o -name "*.js" -o -name "*.py" \) -print0 2>/dev/null || true)
    
    printf '%s\n' "${files[@]}"
}

# Scan example files
scan_examples() {
    local examples=()
    
    if [[ -d "$EXAMPLES_DIR" ]]; then
        while IFS= read -r -d $'\0' file; do
            examples+=("$file")
        done < <(find "$EXAMPLES_DIR" -type f -print0 2>/dev/null || true)
    fi
    
    printf '%s\n' "${examples[@]}"
}

# Generate HTML page
generate_page() {
    log_info "Generating documentation..."
    
    # Parse project metadata
    local project_name=$(parse_yaml "$ARTY_YML" "name")
    local project_version=$(parse_yaml "$ARTY_YML" "version")
    local project_desc=$(parse_yaml "$ARTY_YML" "description")
    local project_author=$(parse_yaml "$ARTY_YML" "author")
    local project_license=$(parse_yaml "$ARTY_YML" "license")
    
    # Use directory name if no project name found
    if [[ -z "$project_name" ]]; then
        project_name=$(basename "$PROJECT_DIR")
    fi
    
    # Read README content
    local readme_content=$(read_file "$README_MD")
    
    # Get icon
    local icon_path=$(get_icon)
    local icon_svg=""
    if [[ -n "$icon_path" ]]; then
        icon_svg=$(cat "$icon_path")
    fi
    
    # Scan files
    local source_files=($(scan_source_files))
    local example_files=($(scan_examples))
    
    # Create output directory
    mkdir -p "$OUTPUT_DIR"
    
    # Generate index.html
