    # Replace placeholders
    sed -i "s/PROJECT_NAME/${project_name}/g" "${OUTPUT_DIR}/index.html"
    sed -i "s/PROJECT_VERSION/${project_version:-1.0.0}/g" "${OUTPUT_DIR}/index.html"
    sed -i "s/PROJECT_DESCRIPTION/${project_desc:-Documentation}/g" "${OUTPUT_DIR}/index.html"
    
    # Handle icon SVG
    if [[ -n "$icon_svg" ]]; then
        # Escape special characters for sed
        icon_svg_escaped=$(echo "$icon_svg" | sed 's/[&/\]/\\&/g' | tr '\n' ' ')
        sed -i "s|PROJECT_ICON_SVG|${icon_svg_escaped}|g" "${OUTPUT_DIR}/index.html"
    else
        sed -i "s|PROJECT_ICON_SVG|<svg class=\"w-full h-full\" fill=\"currentColor\" viewBox=\"0 0 24 24\"><path d=\"M13 2L3 14h9l-1 8 10-12h-9l1-8z\"/></svg>|g" "${OUTPUT_DIR}/index.html"
    fi
    
    # Handle author display
    if [[ -n "$project_author" ]]; then
        sed -i "s|PROJECT_AUTHOR_DISPLAY|<span>👤 ${project_author}</span>|g" "${OUTPUT_DIR}/index.html"
    else
        sed -i "s|PROJECT_AUTHOR_DISPLAY||g" "${OUTPUT_DIR}/index.html"
    fi
    
    # Handle license display
    if [[ -n "$project_license" ]]; then
        sed -i "s|PROJECT_LICENSE_DISPLAY|<span>📜 ${project_license}</span>|g" "${OUTPUT_DIR}/index.html"
    else
        sed -i "s|PROJECT_LICENSE_DISPLAY||g" "${OUTPUT_DIR}/index.html"
    fi
    
    # Process README content
    if [[ -n "$readme_content" ]]; then
        readme_html=$(markdown_to_html "$readme_content")
        # Use a temporary file for complex replacements
        echo "$readme_html" > /tmp/readme_tmp.html
        sed -i "/README_CONTENT_HTML/r /tmp/readme_tmp.html" "${OUTPUT_DIR}/index.html"
        sed -i "/README_CONTENT_HTML/d" "${OUTPUT_DIR}/index.html"
        rm -f /tmp/readme_tmp.html
    else
        sed -i "s|README_CONTENT_HTML|<p class=\"text-slate-600 dark:text-slate-400\">No README.md found.</p>|g" "${OUTPUT_DIR}/index.html"
    fi
    
    # Generate source files HTML
    local source_html=""
    if [[ ${#source_files[@]} -gt 0 ]]; then
        for file in "${source_files[@]}"; do
            local rel_path="${file#${PROJECT_DIR}/}"
            local filename=$(basename "$file")
            local lang=$(detect_language "$file")
            local content=$(cat "$file" | sed 's/&/\&amp;/g; s/</\&lt;/g; s/>/\&gt;/g; s/"/\&quot;/g')
            
            source_html+="<div class=\"bg-white dark:bg-slate-800 rounded-xl shadow-lg overflow-hidden card-hover\">"
