    echo "$source_html" > /tmp/source_tmp.html
    sed -i "/SOURCE_FILES_HTML/r /tmp/source_tmp.html" "${OUTPUT_DIR}/index.html"
    sed -i "/SOURCE_FILES_HTML/d" "${OUTPUT_DIR}/index.html"
    rm -f /tmp/source_tmp.html
    
    # Generate examples HTML
