            local filename=$(basename "$file")
            local lang=$(detect_language "$file")
            local content=$(cat "$file" | sed 's/&/\&amp;/g; s/</\&lt;/g; s/>/\&gt;/g; s/"/\&quot;/g')
            
            examples_html+="<div class=\"bg-white dark:bg-slate-800 rounded-xl shadow-lg overflow-hidden card-hover\">"
            examples_html+="<div class=\"bg-gradient-to-r from-green-500 to-green-600 px-6 py-4\">"
            examples_html+="<h3 class=\"text-xl font-semibold text-white flex items-center\">"
            examples_html+="<svg class=\"w-5 h-5 mr-2\" fill=\"currentColor\" viewBox=\"0 0 20 20\"><path fill-rule=\"evenodd\" d=\"M3 5a2 2 0 012-2h10a2 2 0 012 2v8a2 2 0 01-2 2h-2.22l.123.489.804.804A1 1 0 0113 18H7a1 1 0 01-.707-1.707l.804-.804L7.22 15H5a2 2 0 01-2-2V5zm5.771 7H5V5h10v7H8.771z\" clip-rule=\"evenodd\"/></svg>"
            examples_html+="${filename}</h3>"
            examples_html+="<p class=\"text-green-100 text-sm mt-1\">${rel_path}</p>"
            examples_html+="</div>"
            examples_html+="<div class=\"p-6\">"
            examples_html+="<pre><code class=\"language-${lang}\">${content}</code></pre>"
            examples_html+="</div></div>"
        done
    else
        examples_html="<p class=\"text-center text-slate-600 dark:text-slate-400\">No example files found.</p>"
    fi
    
    echo "$examples_html" > /tmp/examples_tmp.html
    sed -i "/EXAMPLE_FILES_HTML/r /tmp/examples_tmp.html" "${OUTPUT_DIR}/index.html"
    sed -i "/EXAMPLE_FILES_HTML/d" "${OUTPUT_DIR}/index.html"
    rm -f /tmp/examples_tmp.html
    
    log_success "Documentation generated at: ${OUTPUT_DIR}/index.html"
}

# Show usage
show_usage() {
    cat << EOF
leaf.sh - Beautiful documentation generator for arty.sh projects

USAGE:
    leaf.sh [project-dir]

ARGUMENTS:
    project-dir    Path to arty.sh project (default: current directory)

DESCRIPTION:
    Generates a beautiful static HTML documentation website from your arty.sh
    project, including README, source files, examples, and project metadata.

FEATURES:
    • Modern, responsive design with Tailwind CSS v4
    • Syntax highlighting for code blocks
    • Dark/light theme toggle
    • Automatic language detection
    • Smooth animations and transitions
    • Mobile-friendly layout

EXAMPLES:
    # Generate docs for current directory
    leaf.sh

    # Generate docs for specific project
    leaf.sh /path/to/my-project

OUTPUT:
    Documentation will be generated in: [project-dir]/docs/index.html

EOF
}

# Main function
main() {
    # Check for help flag
    if [[ "${1:-}" == "-h" ]] || [[ "${1:-}" == "--help" ]]; then
        show_usage
        exit 0
    fi
    
    echo -e "${CYAN}"
    echo "╔═══════════════════════════════════════════╗"
    echo "║                                           ║"
    echo "║      🌿 leaf.sh Generator 🌿      ║"
    echo "║                                           ║"
    echo "║    Beautiful docs for arty.sh projects   ║"
    echo "║                                           ║"
    echo "╚═══════════════════════════════════════════╝"
    echo -e "${NC}"
    echo
    
    # Check if project directory exists
    if [[ ! -d "$PROJECT_DIR" ]]; then
        log_error "Project directory not found: $PROJECT_DIR"
        exit 1
    fi
    
    log_info "Scanning project: $PROJECT_DIR"
    
    # Check for arty.yml
    if [[ ! -f "$ARTY_YML" ]]; then
        log_warn "No arty.yml found. Generating basic documentation..."
    fi
    
    # Generate documentation
    generate_page
    
    echo
    echo -e "${GREEN}═══════════════════════════════════════════${NC}"
    echo -e "${GREEN}Documentation generated successfully! 🎉${NC}"
    echo -e "${GREEN}═══════════════════════════════════════════${NC}"
    echo
    echo -e "📂 Output: ${CYAN}${OUTPUT_DIR}/index.html${NC}"
    echo -e "🌐 Open in browser:"
    echo -e "   ${BLUE}file://${OUTPUT_DIR}/index.html${NC}"
    echo
}

# Run main function
main "$@"
